import { api } from "@/lib/api/axios";
import { TotalStats } from "../types/dashboard.types";
import { DASHBOARD_TOTAL_ROUTES } from "../routes/dashboard-total.routes";


export const getDepartmentsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_ROUTES.getDepartmentsTotalStats);
}

export const getJobsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_ROUTES.getJobsTotalStats);
}

export const getApplicationsTotalStats = () => {
    return api.get<TotalStats>(DASHBOARD_TOTAL_ROUTES.getApplicationsTotalStats);
}
